<script setup lang="ts">import{onMounted,ref}from'vue';import{useI18n}from'vue-i18n';import{clearDebugLogs,deleteDebugLog,getDebugLog,listDebugLogs}from'@/api/diagnostics';import DebugLogDetail from'@/components/DebugLogDetail.vue';import type{DebugLogStatus}from'@/types/monitor';const{t}=useI18n();const status=ref<DebugLogStatus|null>(null),detail=ref<Record<string,unknown>|null>(null),selected=ref(''),loading=ref(false),error=ref(''),busy=ref(false);async function load(){loading.value=true;error.value='';try{status.value=await listDebugLogs()}catch(e){error.value=e instanceof Error?e.message:''}finally{loading.value=false}}async function open(id:string){selected.value=id;detail.value=null;try{detail.value=await getDebugLog(id)}catch(e){error.value=e instanceof Error?e.message:''}}async function remove(){if(!selected.value||busy.value||!confirm(t('debugLogs.deleteConfirm')))return;busy.value=true;try{await deleteDebugLog(selected.value);selected.value='';detail.value=null;await load()}finally{busy.value=false}}async function clear(){if(busy.value||!confirm(t('debugLogs.clearConfirm')))return;busy.value=true;try{await clearDebugLogs();selected.value='';detail.value=null;await load()}finally{busy.value=false}}async function copy(text:string){await navigator.clipboard.writeText(text)}onMounted(load)</script><template><section class="page diagnostics-page"><header class="page-heading"><div><p class="eyebrow">{{t('debugLogs.eyebrow')}}</p><h1>{{t('debugLogs.title')}}</h1></div><div class="button-row"><button :disabled="loading" @click="load">{{t('debugLogs.refresh')}}</button><button :disabled="busy||!status?.logs.length" @click="clear">{{t('debugLogs.clear')}}</button></div></header><p v-if="loading">{{t('debugLogs.loading')}}</p><p v-if="error" class="error-text">{{error}}</p><p v-if="status&&!status.logs.length">{{t('debugLogs.empty')}}</p><div v-if="status?.logs.length" class="diagnostics-layout"><aside class="log-list"><button v-for="log in status.logs" :key="log.id" :class="{active:selected===log.id}" @click="open(log.id)"><strong>{{log.requestId||log.id}}</strong><span>{{log.timestamp}}</span><small>HTTP {{log.statusCode??'—'}} · {{log.sizeBytes}} B</small></button></aside><main><button v-if="detail" class="danger-button" :disabled="busy" @click="remove">{{t('debugLogs.delete')}}</button><DebugLogDetail v-if="detail" :detail="detail" @copy="copy"/><p v-else>{{t('debugLogs.select')}}</p></main></div></section></template>
